import{_ as s,c as e,o as t,ag as a}from"./chunks/framework.QPV3Ar9-.js";const c=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/guide/kubevirt/kubevirt_install.md","filePath":"en/guide/kubevirt/kubevirt_install.md","lastUpdated":1775281329000}'),n={name:"en/guide/kubevirt/kubevirt_install.md"};function l(r,i,o,p,d,h){return t(),e("div",null,i[0]||(i[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Install the KubeVirt environment, including k3s + KubeVirt + network configuration + port forwarding as a complete set.</p><h2 id="add-swap-memory" tabindex="-1">Add Swap Memory <a class="header-anchor" href="#add-swap-memory" aria-label="Permalink to &quot;Add Swap Memory&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Adding some swap prevents the host from running out of memory.</p></div><p>Unit conversion: entering 1024 creates 1GB of SWAP virtual memory. Virtual memory uses disk space. When actual memory runs out, virtual memory is used automatically, but this brings high I/O and CPU usage.</p><p>It is recommended to create swap no larger than twice the actual memory size.</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/spiritLHLS/addswap/main/addswap.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="environment-installation" tabindex="-1">Environment Installation <a class="header-anchor" href="#environment-installation" aria-label="Permalink to &quot;Environment Installation&quot;">​</a></h2><ul><li>Supported OS: Debian 11+, Ubuntu 20.04+</li><li>Automatically installs k3s (lightweight Kubernetes)</li><li>Automatically deploys KubeVirt operator and CDI (Containerized Data Importer)</li><li>Automatically configures Flannel network plugin and port forwarding</li><li>Automatically detects public IPv6 address and configures IPv6 network (if present)</li><li>Supports x86_64 and ARM64 architecture servers</li></ul><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/kubevirt/main/kubevirtinstall.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>After installation, it is recommended to run <code>kubectl get pods -n kubevirt</code> to verify that the KubeVirt environment is working correctly. All Pods should be in <code>Running</code> state.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The k3s + KubeVirt installation takes some time (usually 5–15 minutes). Please run it inside a screen or tmux session to avoid installation failure due to SSH disconnection.</p></div><h2 id="uninstall-kubevirt-environment" tabindex="-1">Uninstall KubeVirt Environment <a class="header-anchor" href="#uninstall-kubevirt-environment" aria-label="Permalink to &quot;Uninstall KubeVirt Environment&quot;">​</a></h2><p>One-click uninstall of the complete environment, including all virtual machines, k3s, KubeVirt, and auxiliary files:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/kubevirt/main/kubevirtuninstall.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The script will require you to enter <code>yes</code> to confirm before execution. This operation is irreversible. Content deleted includes all virtual machines, images, k3s and all KubeVirt components. Reset procedure: run uninstall first, then run install again to verify the entire installation process from scratch.</p></div>',16)]))}const k=s(n,[["render",l]]);export{c as __pageData,k as default};
